      const raw = localStorage.getItem(SETTINGS_STORAGE_KEY);
      if (!raw) {
        return defaultGameSettings;
      }
      const parsed = JSON.parse(raw) as Partial<GameSettings>;
      return {
        ...defaultGameSettings,
        ...parsed,
      };
    } catch {
      return defaultGameSettings;
    }
