  private resolveActionCard(action: "Slash" | "MistSkip" | "GraveTurn" | "Echo", sourceId: string, explicitTargetId?: string): void {
    let actionToResolve = action;

    if (action === "Echo") {
      if (!this.lastAction) {
        this.emit("effect_resolved", {
          roomId: this.roomId,
          action,
          result: "noop",
        });
        this.endTurn(sourceId);
        return;
      }
      actionToResolve = this.lastAction;
    }

    if (actionToResolve === "Slash") {
      const target = explicitTargetId ? this.getPlayer(explicitTargetId) : this.getNextPlayer(this.turnIndex);
      if (!target) {
        this.endTurn(sourceId);
        return;
      }

      const effect: PendingEffect = {
        id: `effect_${Date.now()}_${this.rng.nextInt(10000)}`,
        sourceId,
        targetId: target.id,
        effectType: "draw",
        amount: 1,
      };

      if (!this.openReactionWindow(effect)) {
        this.resolvePendingEffect(effect);
        this.endTurn(sourceId);
      }

      this.lastAction = "Slash";
      return;
    }

    if (actionToResolve === "MistSkip") {
      this.skipNext = true;
      this.emit("effect_resolved", {
        roomId: this.roomId,
        action: "MistSkip",
      });
      this.lastAction = "MistSkip";
      this.endTurn(sourceId);
      return;
    }

    this.direction = this.direction === 1 ? -1 : 1;
    this.emit("effect_resolved", {
      roomId: this.roomId,
      action: "GraveTurn",
      direction: this.direction,
    });
    this.lastAction = "GraveTurn";
    this.endTurn(sourceId);
  }

