    const timeoutMs = this.roomType === "tutorial" ? this.tutorialReactionTimeoutMs : this.multiplayerReactionTimeoutMs;
    const expiresAt = Date.now() + timeoutMs;

    this.reactionWindow = {
      effect,
      timeoutMs,
      expiresAt,
    };

    this.emit("reaction_window_opened", {
      roomId: this.roomId,
      effectId: effect.id,
      sourceId: effect.sourceId,
      targetId: effect.targetId,
      effectType: effect.effectType,
      timeoutMs,
