  let stderr = '';
  server.stdout.on('data', (chunk) => {
    stdout += chunk.toString();
  });
  server.stderr.on('data', (chunk) => {
    stderr += chunk.toString();
  });

  await waitFor(() => stdout.includes('Servidor listo') || server.exitCode !== null, 7000);
  if (!stdout.includes('Servidor listo')) {
