  const topScore = sortedByScore.length > 0 ? Number(sortedByScore[0].score || 0) : 0;
  const leaderIds = sortedByScore.filter((entry) => Number(entry.score || 0) === topScore).map((entry) => entry.id);

  const state = {
    type: 'state',
    roomCode: room.code,
