    pointLimit: room.pointLimit || DEFAULT_POINT_LIMIT,
    finished: Boolean(room.finished),
    winnerIds: room.winnerIds || [],
    leaderIds,
    topScore,
    pendingPlayers,
    pendingPlayerIds,
    canContinue: canContinueRoom(room),
    phaseStatus: room.finished
